contracts/DocumentVerification.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./TradeRegistry.sol";

/**
 * @title DocumentVerification
 * @dev Handles shipping (Bill of Lading), customs verification, and tax duty flow.
 *
 * ── Document Flow ────────────────────────────────────────────────────────────
 *  1. Shipping company calls issueBillOfLading(tradeId, ipfsHash)
 *     → Stores BoL IPFS CID on-chain → status: GOODS_SHIPPED
 *
 *  2. Customs authority verifies goods:
 *     - If cleared: verifyAsCustoms(tradeId, true) → CUSTOMS_CLEARED
 *     - If not:     verifyAsCustoms(tradeId, false) → DUTY_PENDING
 *
 *  3. [If DUTY_PENDING] Tax authority records duty payment:
 *     recordDutyPayment(tradeId) → DUTY_PAID
 *
 *  4. [After DUTY_PAID] Tax authority releases goods:
 *     releaseFromDuty(tradeId) → CUSTOMS_CLEARED
 *
 * ─────────────────────────────────────────────────────────────────────────────
 */
contract DocumentVerification {
    TradeRegistry public tradeRegistry;

    // ── Structs ────────────────────────────────────────────────────────────
    struct VerificationState {
        string bolIpfsHash;        // IPFS CID of the Bill of Lading
        string customsCertIpfsHash;// IPFS CID of customs clearance certificate (optional)
        bool   bolIssued;
        bool   customsCleared;
        bool   dutyRequired;
        bool   dutyPaid;
    }

    // ── Storage ────────────────────────────────────────────────────────────
    mapping(uint256 => VerificationState) public verifications;

    // ── Events ─────────────────────────────────────────────────────────────
    event BillOfLadingIssued(uint256 indexed tradeId, string ipfsHash, address issuedBy);
    event CustomsDecision(uint256 indexed tradeId, bool cleared, address decidedBy);
    event DutyPaymentRecorded(uint256 indexed tradeId, address recordedBy);
    event GoodsReleasedFromDuty(uint256 indexed tradeId, address releasedBy);

    // ── Constructor ────────────────────────────────────────────────────────
    constructor(address _tradeRegistry) {
        tradeRegistry = TradeRegistry(_tradeRegistry);
    }

    // ── Modifiers ──────────────────────────────────────────────────────────
    modifier onlyShippingCompany(uint256 _tradeId) {
        TradeRegistry.Trade memory trade = tradeRegistry.getTrade(_tradeId);
        require(msg.sender == trade.shippingCompany, "Only assigned shipping company");
        _;
    }

    // ── External Functions ─────────────────────────────────────────────────

    /**
     * @notice Shipping company accepts goods and issues the Bill of Lading.
     *         Stores the BoL IPFS CID on-chain and transitions to GOODS_SHIPPED.
     * @param _tradeId   On-chain trade ID
     * @param _ipfsHash  IPFS CID of the signed Bill of Lading document
     */
    function issueBillOfLading(
        uint256 _tradeId,
        string calldata _ipfsHash
    ) external onlyShippingCompany(_tradeId) {
        TradeRegistry.Trade memory trade = tradeRegistry.getTrade(_tradeId);
        require(
            trade.status == TradeRegistry.TradeStatus.FUNDS_LOCKED,
            "Trade must be in FUNDS_LOCKED status"
        );
        require(bytes(_ipfsHash).length > 0, "IPFS hash required");
        require(!verifications[_tradeId].bolIssued, "BoL already issued");

        verifications[_tradeId].bolIpfsHash = _ipfsHash;
        verifications[_tradeId].bolIssued = true;

        tradeRegistry.updateStatus(_tradeId, TradeRegistry.TradeStatus.GOODS_SHIPPED);
        emit BillOfLadingIssued(_tradeId, _ipfsHash, msg.sender);
    }

    /**
     * @notice Customs authority verifies goods and makes a clearance decision.
     *         - cleared = true  → CUSTOMS_CLEARED (payment flow begins)
     *         - cleared = false → DUTY_PENDING (tax authority must calculate duty)
     * @param _tradeId           On-chain trade ID
     * @param _cleared           Whether goods are cleared (true) or held (false)
     * @param _certIpfsHash      Optional: IPFS CID of customs certificate (pass "" if none)
     */
    function verifyAsCustoms(
        uint256 _tradeId,
        bool _cleared,
        string calldata _certIpfsHash
    ) external {
        TradeRegistry.Trade memory trade = tradeRegistry.getTrade(_tradeId);
        require(trade.status == TradeRegistry.TradeStatus.GOODS_SHIPPED, "Goods not yet shipped");

        VerificationState storage state = verifications[_tradeId];

        if (bytes(_certIpfsHash).length > 0) {
            state.customsCertIpfsHash = _certIpfsHash;
        }

        if (_cleared) {
            state.customsCleared = true;
            tradeRegistry.updateStatus(_tradeId, TradeRegistry.TradeStatus.CUSTOMS_CLEARED);
        } else {
            state.dutyRequired = true;
            tradeRegistry.updateStatus(_tradeId, TradeRegistry.TradeStatus.DUTY_PENDING);
        }

        emit CustomsDecision(_tradeId, _cleared, msg.sender);
    }

    /**
     * @notice Tax authority records that the importer has paid the required duty.
     *         Transitions status to DUTY_PAID.
     */
    function recordDutyPayment(uint256 _tradeId) external {
        TradeRegistry.Trade memory trade = tradeRegistry.getTrade(_tradeId);
        require(trade.status == TradeRegistry.TradeStatus.DUTY_PENDING, "No pending duty");

        VerificationState storage state = verifications[_tradeId];
        require(state.dutyRequired, "Duty was not required");
        require(!state.dutyPaid, "Duty already recorded as paid");

        state.dutyPaid = true;
        tradeRegistry.updateStatus(_tradeId, TradeRegistry.TradeStatus.DUTY_PAID);
        emit DutyPaymentRecorded(_tradeId, msg.sender);
    }

    /**
     * @notice Tax authority releases goods from customs after duty payment.
     *         Transitions status to CUSTOMS_CLEARED so payment flow can proceed.
     */
    function releaseFromDuty(uint256 _tradeId) external {
        TradeRegistry.Trade memory trade = tradeRegistry.getTrade(_tradeId);
        require(trade.status == TradeRegistry.TradeStatus.DUTY_PAID, "Duty not paid yet");

        VerificationState storage state = verifications[_tradeId];
        require(state.dutyPaid, "Duty not recorded as paid");

        state.customsCleared = true;
        tradeRegistry.updateStatus(_tradeId, TradeRegistry.TradeStatus.CUSTOMS_CLEARED);
        emit GoodsReleasedFromDuty(_tradeId, msg.sender);
    }

    /**
     * @notice Read the full verification state for a trade.
     */
    function getVerification(uint256 _tradeId) external view returns (VerificationState memory) {
        return verifications[_tradeId];
    }

    /**
     * @notice Read just the IPFS hash of the Bill of Lading for a trade.
     */
    function getBolIpfsHash(uint256 _tradeId) external view returns (string memory) {
        return verifications[_tradeId].bolIpfsHash;
    }
}

contracts/LetterOfCredit.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./TradeRegistry.sol";

/**
 * @title LetterOfCredit
 * @dev Manages the full LoC lifecycle:
 *      1. Importer bank uploads LoC document → stores IPFS hash on-chain → LOC_UPLOADED
 *      2. Exporter bank approves the LoC → LOC_APPROVED
 *      3. Importer bank locks funds in escrow → FUNDS_LOCKED
 *
 * ── IPFS Document Flow ───────────────────────────────────────────────────────
 *  Backend uploads file → Pinata IPFS → returns CID
 *  Importer bank calls uploadLocDocument(tradeId, CID) → CID stored on-chain
 *  Anyone can read locDocHash[tradeId] and retrieve the document via IPFS gateway
 * ─────────────────────────────────────────────────────────────────────────────
 */
contract LetterOfCredit {
    TradeRegistry public tradeRegistry;

    // ── Structs ────────────────────────────────────────────────────────────
    struct LoC {
        uint256 tradeId;
        uint256 amount;
        uint256 expiry;
        string  locDocIpfsHash;   // IPFS CID of the LoC document
        bool    isUploaded;
        bool    isApproved;
        bool    fundsLocked;
    }

    // ── Storage ────────────────────────────────────────────────────────────
    mapping(uint256 => LoC) public locs;

    // ── Events ─────────────────────────────────────────────────────────────
    event LoCDocumentUploaded(uint256 indexed tradeId, string ipfsHash, address uploadedBy);
    event LoCApproved(uint256 indexed tradeId, address approvedBy);
    event FundsLocked(uint256 indexed tradeId, uint256 amount);

    // ── Constructor ────────────────────────────────────────────────────────
    constructor(address _tradeRegistry) {
        tradeRegistry = TradeRegistry(_tradeRegistry);
    }

    // ── Modifiers ──────────────────────────────────────────────────────────
    modifier onlyIssuingBank(uint256 _tradeId) {
        TradeRegistry.Trade memory trade = tradeRegistry.getTrade(_tradeId);
        require(msg.sender == trade.issuingBank, "Only issuing bank (importer bank)");
        _;
    }

    modifier onlyAdvisingBank(uint256 _tradeId) {
        TradeRegistry.Trade memory trade = tradeRegistry.getTrade(_tradeId);
        require(msg.sender == trade.advisingBank, "Only advising bank (exporter bank)");
        _;
    }

    // ── External Functions ─────────────────────────────────────────────────

    /**
     * @notice Importer bank uploads the LoC document (stored on IPFS).
     *         Initialises the LoC record and transitions to LOC_UPLOADED.
     * @param _tradeId   On-chain trade ID
     * @param _expiry    Unix timestamp for LoC expiry
     * @param _ipfsHash  IPFS CID of the uploaded LoC PDF/document
     */
    function uploadLocDocument(
        uint256 _tradeId,
        uint256 _expiry,
        string calldata _ipfsHash
    ) external onlyIssuingBank(_tradeId) {
        TradeRegistry.Trade memory trade = tradeRegistry.getTrade(_tradeId);
        require(
            trade.status == TradeRegistry.TradeStatus.LOC_INITIATED,
            "Trade must be in LOC_INITIATED status"
        );
        require(bytes(_ipfsHash).length > 0, "IPFS hash required");

        locs[_tradeId] = LoC({
            tradeId:         _tradeId,
            amount:          trade.amount,
            expiry:          _expiry,
            locDocIpfsHash:  _ipfsHash,
            isUploaded:      true,
            isApproved:      false,
            fundsLocked:     false
        });

        tradeRegistry.updateStatus(_tradeId, TradeRegistry.TradeStatus.LOC_UPLOADED);
        emit LoCDocumentUploaded(_tradeId, _ipfsHash, msg.sender);
    }

    /**
     * @notice Exporter bank reviews and approves the uploaded LoC.
     *         Transitions trade to LOC_APPROVED.
     */
    function approveLoC(uint256 _tradeId) external onlyAdvisingBank(_tradeId) {
        TradeRegistry.Trade memory trade = tradeRegistry.getTrade(_tradeId);
        require(trade.status == TradeRegistry.TradeStatus.LOC_UPLOADED, "LoC not yet uploaded");

        LoC storage loc = locs[_tradeId];
        require(loc.isUploaded, "LoC document not uploaded");
        require(!loc.isApproved, "LoC already approved");

        loc.isApproved = true;
        tradeRegistry.updateStatus(_tradeId, TradeRegistry.TradeStatus.LOC_APPROVED);
        emit LoCApproved(_tradeId, msg.sender);
    }

    /**
     * @notice Importer bank locks funds in escrow after LoC approval.
     *         Transitions trade to FUNDS_LOCKED.
     */
    function lockFunds(uint256 _tradeId) external onlyIssuingBank(_tradeId) {
        TradeRegistry.Trade memory trade = tradeRegistry.getTrade(_tradeId);
        require(trade.status == TradeRegistry.TradeStatus.LOC_APPROVED, "LoC not approved yet");

        LoC storage loc = locs[_tradeId];
        require(!loc.fundsLocked, "Funds already locked");

        loc.fundsLocked = true;
        tradeRegistry.updateStatus(_tradeId, TradeRegistry.TradeStatus.FUNDS_LOCKED);
        emit FundsLocked(_tradeId, loc.amount);
    }

    /**
     * @notice Read the LoC record and its IPFS document hash for a trade.
     */
    function getLoC(uint256 _tradeId) external view returns (LoC memory) {
        return locs[_tradeId];
    }
}

contracts/PaymentSettlement.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./TradeRegistry.sol";

/**
 * @title PaymentSettlement
 * @dev Manages the final payment authorization and off-chain settlement confirmation.
 *
 * ── Payment Flow ─────────────────────────────────────────────────────────────
 *  1. After CUSTOMS_CLEARED:
 *     Importer bank calls authorizePayment(tradeId) → PAYMENT_AUTHORIZED
 *
 *  2. Off-chain: Bank-to-bank SWIFT/SEPA settlement happens.
 *
 *  3. Exporter bank confirms receipt of funds:
 *     confirmSettlement(tradeId) → SETTLEMENT_CONFIRMED → COMPLETED
 *
 * Note: Actual fund transfer is off-chain (traditional banking). This contract
 *       records the authorization and confirmation events on-chain for the
 *       immutable audit trail visible to all stakeholders (incl. Regulator).
 * ─────────────────────────────────────────────────────────────────────────────
 */
contract PaymentSettlement {
    TradeRegistry public tradeRegistry;

    // ── Structs ────────────────────────────────────────────────────────────
    struct Settlement {
        uint256 tradeId;
        uint256 amount;
        bool    paymentAuthorized;
        bool    settlementConfirmed;
        uint256 authorizedAt;
        uint256 confirmedAt;
    }

    // ── Storage ────────────────────────────────────────────────────────────
    mapping(uint256 => Settlement) public settlements;

    // ── Events ─────────────────────────────────────────────────────────────
    event PaymentAuthorized(uint256 indexed tradeId, uint256 amount, address authorizedBy);
    event SettlementConfirmed(uint256 indexed tradeId, address confirmedBy);
    event TradeCompleted(uint256 indexed tradeId);

    // ── Constructor ────────────────────────────────────────────────────────
    constructor(address _tradeRegistry) {
        tradeRegistry = TradeRegistry(_tradeRegistry);
    }

    // ── Modifiers ──────────────────────────────────────────────────────────
    modifier onlyIssuingBank(uint256 _tradeId) {
        TradeRegistry.Trade memory trade = tradeRegistry.getTrade(_tradeId);
        require(msg.sender == trade.issuingBank, "Only issuing bank (importer bank)");
        _;
    }

    modifier onlyAdvisingBank(uint256 _tradeId) {
        TradeRegistry.Trade memory trade = tradeRegistry.getTrade(_tradeId);
        require(msg.sender == trade.advisingBank, "Only advising bank (exporter bank)");
        _;
    }

    // ── External Functions ─────────────────────────────────────────────────

    /**
     * @notice Importer bank authorizes payment after customs clearance.
     *         Transitions trade to PAYMENT_AUTHORIZED.
     *         Off-chain bank settlement will follow after this.
     * @param _tradeId  On-chain trade ID
     */
    function authorizePayment(uint256 _tradeId) external onlyIssuingBank(_tradeId) {
        TradeRegistry.Trade memory trade = tradeRegistry.getTrade(_tradeId);
        require(
            trade.status == TradeRegistry.TradeStatus.CUSTOMS_CLEARED,
            "Customs must be cleared first"
        );

        Settlement storage s = settlements[_tradeId];
        require(!s.paymentAuthorized, "Payment already authorized");

        s.tradeId           = _tradeId;
        s.amount            = trade.amount;
        s.paymentAuthorized = true;
        s.authorizedAt      = block.timestamp;

        tradeRegistry.updateStatus(_tradeId, TradeRegistry.TradeStatus.PAYMENT_AUTHORIZED);
        emit PaymentAuthorized(_tradeId, trade.amount, msg.sender);
    }

    /**
     * @notice Exporter bank confirms that off-chain bank settlement has completed.
     *         Transitions trade to SETTLEMENT_CONFIRMED then immediately to COMPLETED.
     * @param _tradeId  On-chain trade ID
     */
    function confirmSettlement(uint256 _tradeId) external onlyAdvisingBank(_tradeId) {
        TradeRegistry.Trade memory trade = tradeRegistry.getTrade(_tradeId);
        require(
            trade.status == TradeRegistry.TradeStatus.PAYMENT_AUTHORIZED,
            "Payment not yet authorized"
        );

        Settlement storage s = settlements[_tradeId];
        require(s.paymentAuthorized, "Payment not authorized on record");
        require(!s.settlementConfirmed, "Settlement already confirmed");

        s.settlementConfirmed = true;
        s.confirmedAt         = block.timestamp;

        // Transition: PAYMENT_AUTHORIZED → SETTLEMENT_CONFIRMED → COMPLETED
        tradeRegistry.updateStatus(_tradeId, TradeRegistry.TradeStatus.SETTLEMENT_CONFIRMED);
        emit SettlementConfirmed(_tradeId, msg.sender);

        tradeRegistry.updateStatus(_tradeId, TradeRegistry.TradeStatus.COMPLETED);
        emit TradeCompleted(_tradeId);
    }

    /**
     * @notice Read the settlement record for a trade.
     */
    function getSettlement(uint256 _tradeId) external view returns (Settlement memory) {
        return settlements[_tradeId];
    }
}

contracts/TradeRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

/**
 * @title TradeRegistry
 * @dev Central registry for all trades. Manages participants, state machine,
 *      and authorization of satellite contracts (LoC, DocVerification, Payment).
 *
 * ── State Machine ────────────────────────────────────────────────────────────
 *  OFFER_ACCEPTED  → TRADE_INITIATED (both parties on-chain confirm)
 *  TRADE_INITIATED → LOC_INITIATED   (importer selects bank)
 *  LOC_INITIATED   → LOC_UPLOADED    (importer bank uploads doc + IPFS hash)
 *  LOC_UPLOADED    → LOC_APPROVED    (exporter bank approves)
 *  LOC_APPROVED    → FUNDS_LOCKED    (importer bank locks funds)
 *  FUNDS_LOCKED    → GOODS_SHIPPED   (shipping company issues BoL)
 *  GOODS_SHIPPED   → CUSTOMS_CLEARED or DUTY_PENDING (customs decision)
 *  DUTY_PENDING    → DUTY_PAID       (importer pays duty via bank)
 *  DUTY_PAID       → CUSTOMS_CLEARED (tax authority releases)
 *  CUSTOMS_CLEARED → PAYMENT_AUTHORIZED (importer bank authorizes)
 *  PAYMENT_AUTHORIZED → SETTLEMENT_CONFIRMED (exporter bank confirms)
 *  SETTLEMENT_CONFIRMED → COMPLETED
 * ─────────────────────────────────────────────────────────────────────────────
 */
contract TradeRegistry {

    // ── Enums ──────────────────────────────────────────────────────────────
    enum TradeStatus {
        OFFER_ACCEPTED,        // 0  – Importer accepted exporter offer (DB side triggers)
        TRADE_INITIATED,       // 1  – Both parties confirmed on-chain
        LOC_INITIATED,         // 2  – Importer selected bank; LoC process started
        LOC_UPLOADED,          // 3  – Importer bank uploaded LoC document (IPFS hash stored)
        LOC_APPROVED,          // 4  – Exporter bank approved the LoC
        FUNDS_LOCKED,          // 5  – Importer bank locked funds in escrow
        GOODS_SHIPPED,         // 6  – Shipping company issued Bill of Lading
        CUSTOMS_CLEARED,       // 7  – Customs authority cleared the goods
        DUTY_PENDING,          // 8  – Goods held; tax authority calculating duty
        DUTY_PAID,             // 9  – Importer paid the required duty
        PAYMENT_AUTHORIZED,    // 10 – Importer bank authorized payment release
        SETTLEMENT_CONFIRMED,  // 11 – Exporter bank confirmed off-chain settlement
        COMPLETED,             // 12 – Trade fully completed
        DISPUTED,              // 13 – Trade under dispute
        EXPIRED                // 14 – Trade expired without completion
    }

    // ── Structs ────────────────────────────────────────────────────────────
    struct Trade {
        uint256 tradeId;
        address importer;
        address exporter;
        address issuingBank;    // importer's bank
        address advisingBank;   // exporter's bank
        address shippingCompany;
        TradeStatus status;
        uint256 createdAt;
        uint256 amount;
        bool importerConfirmed; // for TRADE_INITIATED mutual confirmation
        bool exporterConfirmed;
    }

    // ── Storage ────────────────────────────────────────────────────────────
    mapping(uint256 => Trade) public trades;
    mapping(address => bool) public authorizedContracts;
    address public owner;
    uint256 public nextTradeId;

    // ── Events ─────────────────────────────────────────────────────────────
    event TradeCreated(uint256 indexed tradeId, address importer, address exporter, uint256 amount);
    event TradeStatusUpdated(uint256 indexed tradeId, TradeStatus oldStatus, TradeStatus newStatus);
    event TradeConfirmed(uint256 indexed tradeId, address confirmedBy);
    event TradeInitiated(uint256 indexed tradeId);
    event ContractAuthorized(address indexed contractAddress, bool authorized);

    // ── Constructor ────────────────────────────────────────────────────────
    constructor() {
        owner = msg.sender;
    }

    // ── Modifiers ──────────────────────────────────────────────────────────
    modifier onlyOwner() {
        require(msg.sender == owner, "Only owner");
        _;
    }

    modifier onlyAuthorized() {
        require(authorizedContracts[msg.sender] || msg.sender == owner, "Not authorized");
        _;
    }

    modifier onlyParticipant(uint256 _tradeId) {
        Trade storage trade = trades[_tradeId];
        require(
            msg.sender == trade.importer ||
            msg.sender == trade.exporter ||
            msg.sender == trade.issuingBank ||
            msg.sender == trade.advisingBank ||
            msg.sender == trade.shippingCompany,
            "Not a participant"
        );
        _;
    }

    // ── External Functions ─────────────────────────────────────────────────

    /**
     * @notice Create a new on-chain trade record after offer acceptance.
     *         Sets status to OFFER_ACCEPTED. Both parties must then call
     *         confirmTrade() to move to TRADE_INITIATED.
     * @param _exporter      Exporter wallet address
     * @param _issuingBank   Importer's bank wallet address
     * @param _advisingBank  Exporter's bank wallet address
     * @param _amount        Trade value in wei
     */
    function createTrade(
        address _exporter,
        address _issuingBank,
        address _advisingBank,
        uint256 _amount
    ) external returns (uint256) {
        uint256 tradeId = nextTradeId++;
        trades[tradeId] = Trade({
            tradeId:           tradeId,
            importer:          msg.sender,
            exporter:          _exporter,
            issuingBank:       _issuingBank,
            advisingBank:      _advisingBank,
            shippingCompany:   address(0),
            status:            TradeStatus.OFFER_ACCEPTED,
            createdAt:         block.timestamp,
            amount:            _amount,
            importerConfirmed: false,
            exporterConfirmed: false
        });

        emit TradeCreated(tradeId, msg.sender, _exporter, _amount);
        return tradeId;
    }

    /**
     * @notice Importer or exporter confirms the final trade agreement.
     *         When both confirm, status advances to TRADE_INITIATED.
     */
    function confirmTrade(uint256 _tradeId) external {
        Trade storage trade = trades[_tradeId];
        require(trade.status == TradeStatus.OFFER_ACCEPTED, "Trade not in OFFER_ACCEPTED status");
        require(
            msg.sender == trade.importer || msg.sender == trade.exporter,
            "Only importer or exporter"
        );

        if (msg.sender == trade.importer) {
            require(!trade.importerConfirmed, "Importer already confirmed");
            trade.importerConfirmed = true;
        } else {
            require(!trade.exporterConfirmed, "Exporter already confirmed");
            trade.exporterConfirmed = true;
        }

        emit TradeConfirmed(_tradeId, msg.sender);

        if (trade.importerConfirmed && trade.exporterConfirmed) {
            TradeStatus old = trade.status;
            trade.status = TradeStatus.TRADE_INITIATED;
            emit TradeInitiated(_tradeId);
            emit TradeStatusUpdated(_tradeId, old, TradeStatus.TRADE_INITIATED);
        }
    }

    /**
     * @notice Assign a shipping company to the trade.
     *         Called by the importer after funds are locked.
     */
    function assignShippingCompany(uint256 _tradeId, address _shippingCompany) external {
        Trade storage trade = trades[_tradeId];
        require(msg.sender == trade.importer, "Only importer");
        require(trade.status == TradeStatus.FUNDS_LOCKED, "Funds not locked yet");
        require(_shippingCompany != address(0), "Invalid address");
        trade.shippingCompany = _shippingCompany;
    }

    /**
     * @notice Assign an advising bank (exporter bank) to the trade.
     *         Called by the exporter before the LoC is uploaded/approved.
     */
    function assignAdvisingBank(uint256 _tradeId, address _advisingBank) external {
        Trade storage trade = trades[_tradeId];
        require(msg.sender == trade.exporter, "Only exporter");
        require(_advisingBank != address(0), "Invalid address");
        trade.advisingBank = _advisingBank;
    }

    /**
     * @notice Authorize or de-authorize a satellite contract to call updateStatus.
     */
    function setAuthorizedContract(address _contract, bool _authorized) external onlyOwner {
        authorizedContracts[_contract] = _authorized;
        emit ContractAuthorized(_contract, _authorized);
    }

    /**
     * @notice Update trade status. Only callable by authorized satellite contracts or owner.
     */
    function updateStatus(uint256 _tradeId, TradeStatus _newStatus) external onlyAuthorized {
        TradeStatus old = trades[_tradeId].status;
        trades[_tradeId].status = _newStatus;
        emit TradeStatusUpdated(_tradeId, old, _newStatus);
    }

    /**
     * @notice Read a trade record.
     */
    function getTrade(uint256 _tradeId) external view returns (Trade memory) {
        return trades[_tradeId];
    }
}

